function validateScript(source) {
  if (!source || typeof source !== 'string') {
    throw new Error('Script source must be a non-empty string');
  }

  if (source.length > 2000) {
    throw new Error('Script source exceeds maximum length of 2000 characters');
  }

  for (const pattern of DANGEROUS_PATTERNS) {
    if (pattern.test(source)) {
      throw new Error(`Script contains forbidden pattern: ${pattern.source}`);
    }
  }

  // Check for balanced brackets/parens
  let braceCount = 0;
  let parenCount = 0;
  let bracketCount = 0;
  for (const char of source) {
    if (char === '{') braceCount++;
    if (char === '}') braceCount--;
    if (char === '(') parenCount++;
    if (char === ')') parenCount--;
    if (char === '[') bracketCount++;
    if (char === ']') bracketCount--;
    if (braceCount < 0 || parenCount < 0 || bracketCount < 0) {
      throw new Error('Script has unbalanced brackets');
    }
  }
  if (braceCount !== 0 || parenCount !== 0 || bracketCount !== 0) {
    throw new Error('Script has unbalanced brackets');
  }

  return true;
}

function buildBaseQuery(queryParams) {
  const query = {};

  if (queryParams.match) {
    query.match = queryParams.match;
  } else if (queryParams.multi_match) {
    query.multi_match = queryParams.multi_match;
  } else if (queryParams.term) {
    query.term = queryParams.term;
  } else if (queryParams.terms) {
    query.terms = queryParams.terms;
  } else if (queryParams.range) {
    query.range = queryParams.range;
  } else if (queryParams.bool) {
    query.bool = queryParams.bool;
  } else if (queryParams.exists) {
    query.exists = queryParams.exists;
  } else if (queryParams.wildcard) {
    query.wildcard = queryParams.wildcard;
  } else if (queryParams.prefix) {
    query.prefix = queryParams.prefix;
  } else if (queryParams.fuzzy) {
    query.fuzzy = queryParams.fuzzy;
  } else if (queryParams.nested) {
    query.nested = queryParams.nested;
  } else if (queryParams.query_string) {
    query.query_string = queryParams.query_string;
  } else if (queryParams.match_phrase) {
    query.match_phrase = queryParams.match_phrase;
  } else if (queryParams.match_all !== undefined) {
    query.match_all = queryParams.match_all;
  }

  return query;
}

function buildFilters(filters) {
  if (!filters || filters.length === 0) return [];

  return filters.map(filter => {
    switch (filter.type) {
      case 'term':
        return { term: { [filter.field]: filter.value } };
      case 'terms':
        return { terms: { [filter.field]: filter.value } };
      case 'range':
        return { range: { [filter.field]: filter.value } };
      case 'exists':
        return { exists: { field: filter.field } };
      case 'bool':
        return { bool: filter.config };
      case 'nested':
        return { nested: filter.config };
      case 'geo_distance':
        return {
          geo_distance: {
            distance: filter.config.distance,
            [filter.field]: filter.config.location,
          }
        };
      case 'geo_bounding_box':
        return {
          geo_bounding_box: {
            [filter.field]: filter.config,
          }
        };
      default:
        throw new Error(`Unsupported filter type: ${filter.type}`);
    }
  });
}

function buildAggregations(aggregations) {
  if (!aggregations) return undefined;

  const aggs = {};

  for (const [name, aggConfig] of Object.entries(aggregations)) {
    const aggBody = {};

    switch (aggConfig.type) {
      case 'terms':
        aggBody.terms = {
          field: aggConfig.field,
          size: (aggConfig.config && aggConfig.config.size) || 10,
          ...aggConfig.config,
        };
        break;
      case 'range':
        aggBody.range = {
          field: aggConfig.field,
          ranges: aggConfig.config.ranges,
          ...aggConfig.config,
        };
        break;
      case 'date_histogram':
        aggBody.date_histogram = {
          field: aggConfig.field,
          ...aggConfig.config,
        };
        break;
      case 'histogram':
        aggBody.histogram = {
          field: aggConfig.field,
          ...aggConfig.config,
        };
        break;
      case 'avg':
      case 'sum':
      case 'min':
      case 'max':
      case 'cardinality':
      case 'stats':
      case 'extended_stats':
      case 'percentiles':
      case 'value_count':
        aggBody[aggConfig.type] = {
          field: aggConfig.field,
          ...aggConfig.config,
        };
        break;
      case 'nested':
        aggBody.nested = {
          path: aggConfig.config.path,
        };
        break;
      case 'filter':
        aggBody.filter = aggConfig.config.filter;
        break;
      case 'filters':
        aggBody.filters = {
          filters: aggConfig.config.filters,
        };
        break;
      case 'significant_terms':
        aggBody.significant_terms = {
          field: aggConfig.field,
          ...aggConfig.config,
        };
        break;
      default:
        throw new Error(`Unsupported aggregation type: ${aggConfig.type}`);
    }

    if (aggConfig.sub_aggregations) {
      aggBody.aggs = buildAggregations(aggConfig.sub_aggregations);
    }

    aggs[name] = aggBody;
  }

  return aggs;
}

function buildScoredQuery(baseQuery, filters, scoring, predefinedScoring) {
  let innerQuery;

  if (filters && filters.length > 0) {
    const filterClauses = buildFilters(filters);
    innerQuery = {
      bool: {
        must: [baseQuery],
        filter: filterClauses,
      }
    };
  } else {
    innerQuery = baseQuery;
  }

  // Use predefined scoring template
  if (predefinedScoring) {
    const template = SCORING_TEMPLATES[predefinedScoring.template];
    if (!template) {
      throw new Error(`Unknown scoring template: ${predefinedScoring.template}`);
    }

    const scoringConfig = template.generateScript(predefinedScoring.params || {});

    if (scoringConfig.functionScore) {
      return {
        function_score: {
          query: innerQuery,
          ...scoringConfig.functionScore,
        }
      };
    }

    if (scoringConfig.scriptScore) {
      return {
        script_score: {
          query: innerQuery,
          ...scoringConfig.scriptScore,
        }
      };
    }
  }

  // Use custom script scoring
  if (scoring && scoring.script) {
    validateScript(scoring.script.source);

    const scriptScoreQuery = {
      script_score: {
        query: innerQuery,
        script: {
          source: scoring.script.source,
          lang: scoring.script.lang || 'painless',
        },
      }
    };

    if (scoring.script.params && Object.keys(scoring.script.params).length > 0) {
      scriptScoreQuery.script_score.script.params = scoring.script.params;
    }

    if (scoring.min_score !== undefined) {
      scriptScoreQuery.script_score.min_score = scoring.min_score;
    }

    if (scoring.boost_mode) {
      scriptScoreQuery.script_score.boost_mode = scoring.boost_mode;
    }

    return scriptScoreQuery;
  }

  return innerQuery;
}

function buildElasticsearchQuery(params) {
  const baseQuery = buildBaseQuery(params.query);
  const scoredQuery = buildScoredQuery(baseQuery, params.filters, params.scoring, params.predefinedScoring);

  const body = {
    query: scoredQuery,
    track_total_hits: params.track_total_hits !== undefined ? params.track_total_hits : true,
  };

  // Pagination
  if (params.pagination) {
    body.from = params.pagination.from || 0;
    body.size = params.pagination.size || 10;
  } else {
    body.from = 0;
    body.size = 10;
  }

  // Sort
  if (params.sort) {
    body.sort = params.sort;
  }

  // Source filtering
  if (params.source !== undefined) {
    body._source = params.source;
  }

  // Highlighting
  if (params.highlight) {
    body.highlight = params.highlight;
  }

  // Aggregations
  if (params.aggregations) {
    body.aggs = buildAggregations(params.aggregations);
  }

  // Field collapsing
  if (params.collapse) {
    body.collapse = params.collapse;
  }

  // Suggestions
  if (params.suggest) {
    body.suggest = params.suggest;
  }

  return body;
}

// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path,
        })),
      });
    }

    const esBody = buildElasticsearchQuery(params);

    console.log('Elasticsearch Query:', JSON.stringify(esBody, null, 2));

    const result = await esClient.search({
      index: params.index,
      body: esBody,
    });

    const response = {
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight,
        sort: hit.sort,
        inner_hits: hit.inner_hits,
      })),
      took: result.took,
      timed_out: result.timed_out,
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    if (result.suggest) {
      response.suggest = result.suggest;
    }

    res.json(response);
  } catch (err) {
    console.error('Search error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: err.message || 'Internal server error',
    });
  }
});

